<?php
 namespace League\CommonMark\Extension\SmartPunct; use League\CommonMark\Inline\Element\Text; use League\CommonMark\Inline\Parser\InlineParserInterface; use League\CommonMark\InlineParserContext; final class PunctuationParser implements InlineParserInterface { public function getCharacters(): array { return ['-', '.']; } public function parse(InlineParserContext $inlineContext): bool { $cursor = $inlineContext->getCursor(); $ch = $cursor->getCharacter(); if ($ch === '.' && $matched = $cursor->match('/^\\.( ?\\.)\\1/')) { $inlineContext->getContainer()->appendChild(new Text('…')); return true; } elseif ($ch === '-' && $matched = $cursor->match('/^(?<!-)(-{2,})/')) { $count = strlen($matched); $en_dash = '–'; $en_count = 0; $em_dash = '—'; $em_count = 0; if ($count % 3 === 0) { $em_count = $count / 3; } elseif ($count % 2 === 0) { $en_count = $count / 2; } elseif ($count % 3 === 2) { $em_count = ($count - 2) / 3; $en_count = 1; } else { $em_count = ($count - 4) / 3; $en_count = 2; } $inlineContext->getContainer()->appendChild(new Text( str_repeat($em_dash, (int) $em_count) . str_repeat($en_dash, (int) $en_count) )); return true; } return false; } } 